// ── Extract inputs from the webhook trigger ──
const webhookData = $('Webhook Trigger').first().json;
const body = webhookData.body ?? webhookData;
const headers = webhookData.headers ?? {};

const fileId = body.fileId ?? `kb_${Date.now()}`;
const orgId = body.orgId ?? 'unknown_org';
const callbackUrl = body.callbackUrl ?? '';
const url = body.url ?? null;
const fileName = body.file?.originalFilename ?? body.fileName ?? (url ? new URL(url).hostname : 'unknown');

// Check if there's a binary attachment from the webhook
let hasBinary = false;
try {
  const binaryData = $('Webhook Trigger').first().binary;
  hasBinary = binaryData && Object.keys(binaryData).length > 0;
} catch (e) {
  hasBinary = false;
}

return [{
  json: {
    fileId,
    orgId,
    callbackUrl,
    url,
    fileName,
    hasBinary,
    source: url ? 'url' : 'file'
  }
}];

// ── Route: file or URL ──
const item = $input.first().json;

let extractedText = '';

if (item.source === 'url' && item.url) {
  // Fetch URL content
  const resp = await fetch(item.url, {
    headers: { 'User-Agent': 'Mozilla/5.0 (compatible; KBIngest/1.0)' },
    signal: AbortSignal.timeout(15000)
  });
  if (!resp.ok) throw new Error(`Failed to fetch URL: ${resp.status}`);
  const html = await resp.text();
  // Strip HTML tags for a rough text extraction
  extractedText = html
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/\s{2,}/g, ' ')
    .trim();
} else {
  // For file uploads — read the binary data attached by the webhook
  try {
    const binaryData = $('Webhook Trigger').first().binary;
    if (binaryData) {
      const key = Object.keys(binaryData)[0];
      if (key) {
        const buffer = await this.helpers.getBinaryDataBuffer(0, key);
        const content = buffer.toString('utf-8');

        const fn = (item.fileName ?? '').toLowerCase();
        if (fn.endsWith('.csv')) {
          // CSV: each row becomes a line
          extractedText = content;
        } else if (fn.endsWith('.json')) {
          // JSON: flatten to readable text
          try {
            const parsed = JSON.parse(content);
            const flatten = (obj, prefix = '') => {
              let lines = [];
              for (const [k, v] of Object.entries(obj)) {
                const key = prefix ? `${prefix}.${k}` : k;
                if (v && typeof v === 'object' && !Array.isArray(v)) {
                  lines.push(...flatten(v, key));
                } else {
                  lines.push(`${key}: ${JSON.stringify(v)}`);
                }
              }
              return lines;
            };
            if (Array.isArray(parsed)) {
              extractedText = parsed.map((row, i) => `Row ${i+1}: ${JSON.stringify(row)}`).join('\n');
            } else {
              extractedText = flatten(parsed).join('\n');
            }
          } catch {
            extractedText = content;
          }
        } else if (fn.endsWith('.sql')) {
          // SQL dump: extract INSERT statements and readable parts
          const inserts = content.match(/INSERT\s+INTO[^;]+;/gi) || [];
          const creates = content.match(/CREATE\s+TABLE[^;]+;/gi) || [];
          extractedText = [...creates, ...inserts].join('\n\n') || content;
        } else {
          // PDF / DOCX / other: use raw text (n8n Extract node handles these better,
          // but as a fallback we try raw UTF-8)
          extractedText = content.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, ' ').trim();
          if (extractedText.length < 50) {
            extractedText = `[Binary file: ${item.fileName} — ${buffer.length} bytes. For PDF/DOCX, consider using n8n Extract from File node.]`;
          }
        }
      }
    }
  } catch (e) {
    extractedText = `Error reading file: ${e.message}`;
  }
}

if (!extractedText || extractedText.length < 10) {
  throw new Error(`No text could be extracted from ${item.source}: ${item.fileName ?? item.url}`);
}

return [{
  json: {
    ...item,
    extractedText,
    textLength: extractedText.length
  }
}];

// ── Chunk text into ~500-token (~2000 char) segments with 200-char overlap ──
const item = $input.first().json;
const text = item.extractedText;
const CHUNK_SIZE = 2000;
const OVERLAP = 200;

const chunks = [];
let start = 0;

while (start < text.length) {
  let end = Math.min(start + CHUNK_SIZE, text.length);

  // Try to break at sentence boundary
  if (end < text.length) {
    const lastPeriod = text.lastIndexOf('. ', end);
    const lastNewline = text.lastIndexOf('\n', end);
    const breakPoint = Math.max(lastPeriod, lastNewline);
    if (breakPoint > start + CHUNK_SIZE * 0.5) {
      end = breakPoint + 1;
    }
  }

  const chunk = text.slice(start, end).trim();
  if (chunk.length > 20) {
    chunks.push(chunk);
  }

  start = end - OVERLAP;
  if (start >= text.length) break;
}

// Return metadata + all chunks
return [{
  json: {
    fileId: item.fileId,
    orgId: item.orgId,
    callbackUrl: item.callbackUrl,
    fileName: item.fileName,
    chunkCount: chunks.length,
    chunks
  }
}];

// ── Embed all chunks via Ollama nomic-embed-text ──
const item = $input.first().json;
const OLLAMA_URL = 'http://localhost:11434/api/embeddings';
const MODEL = 'nomic-embed-text';
const BATCH_SIZE = 10; // Process in batches to avoid overwhelming Ollama

const vectors = [];

for (let i = 0; i < item.chunks.length; i += BATCH_SIZE) {
  const batch = item.chunks.slice(i, i + BATCH_SIZE);

  const batchResults = await Promise.all(
    batch.map(async (chunkText, batchIdx) => {
      const idx = i + batchIdx;
      const resp = await fetch(OLLAMA_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ model: MODEL, prompt: chunkText })
      });

      if (!resp.ok) {
        const errText = await resp.text();
        throw new Error(`Ollama embedding failed for chunk ${idx}: ${resp.status} ${errText}`);
      }

      const data = await resp.json();
      return {
        id: `${item.fileId}_chunk_${idx}`,
        values: data.embedding,
        metadata: {
          orgId: item.orgId,
          fileId: item.fileId,
          fileName: item.fileName,
          chunkIndex: idx,
          text: chunkText.slice(0, 3600) // Pinecone metadata limit ~40KB
        }
      };
    })
  );

  vectors.push(...batchResults);
}

return [{
  json: {
    fileId: item.fileId,
    orgId: item.orgId,
    callbackUrl: item.callbackUrl,
    fileName: item.fileName,
    chunkCount: item.chunkCount,
    vectorCount: vectors.length,
    vectors
  }
}];

// ── Upsert vectors to Pinecone ──
const item = $input.first().json;

// Pinecone config — uses the same creds as the voice-rag-query workflow
const PINECONE_API_KEY = 'pcsk_44U1wN_QGfdUdgsYtkgGHVu6UJ2K77GK3eDBgPL9aK7DfWNdgi3HS3AtviDmQenUyx5jZE';
const PINECONE_INDEX = 'vad';

// Discover Pinecone host from the index description
const descResp = await fetch(`https://api.pinecone.io/indexes/${PINECONE_INDEX}`, {
  headers: { 'Api-Key': PINECONE_API_KEY, 'Accept': 'application/json' }
});
if (!descResp.ok) {
  throw new Error(`Pinecone describe index failed: ${descResp.status} ${await descResp.text()}`);
}
const indexInfo = await descResp.json();
const host = indexInfo.host; // e.g. 'vad-xxxxx.svc.xxx.pinecone.io'

// Batch upsert (Pinecone recommends max 100 vectors per request)
const BATCH = 100;
let upserted = 0;

for (let i = 0; i < item.vectors.length; i += BATCH) {
  const batch = item.vectors.slice(i, i + BATCH);

  const upsertResp = await fetch(`https://${host}/vectors/upsert`, {
    method: 'POST',
    headers: {
      'Api-Key': PINECONE_API_KEY,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ vectors: batch })
  });

  if (!upsertResp.ok) {
    const errBody = await upsertResp.text();
    throw new Error(`Pinecone upsert failed at batch ${i}: ${upsertResp.status} ${errBody}`);
  }

  const result = await upsertResp.json();
  upserted += result.upsertedCount ?? batch.length;
}

return [{
  json: {
    fileId: item.fileId,
    orgId: item.orgId,
    callbackUrl: item.callbackUrl,
    fileName: item.fileName,
    chunkCount: item.chunkCount,
    vectorCount: upserted
  }
}];

// ── Error handler: notify callback of failure ──
const allItems = $input.all();
const errorItem = allItems[0]?.json ?? {};

// Try to find fileId and callbackUrl from the execution context
let fileId = errorItem.fileId;
let callbackUrl = errorItem.callbackUrl;
let errorMessage = 'Unknown pipeline error';

// Try to extract from earlier nodes if not in error item
try {
  const extracted = $('Extract Inputs').first().json;
  fileId = fileId ?? extracted.fileId;
  callbackUrl = callbackUrl ?? extracted.callbackUrl;
} catch (e) {}

// Get the actual error message
try {
  const err = $input.first();
  if (err.json?.message) errorMessage = err.json.message;
  else if (err.json?.error) errorMessage = typeof err.json.error === 'string' ? err.json.error : JSON.stringify(err.json.error);
  else if (err.error) errorMessage = err.error.message ?? String(err.error);
} catch (e) {
  errorMessage = e.message;
}

if (callbackUrl && fileId) {
  await fetch(callbackUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      fileId,
      stage: 'failed',
      progress: 0,
      errorMessage: errorMessage.slice(0, 500)
    })
  });
}

return [{ json: { fileId, stage: 'failed', errorMessage } }];
